// src/pages/HomeScreen.js
import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// ✅ DO NOT TOUCH: taxi.png already includes arch + big green pin + taxi
const taxiImg = require("../../assets/taxi.png");

// ✅ urban.png already includes crest + “Communauté Urbaine de Yaoundé”
const cityLogo = require("../../assets/urban.png");

const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const plateNumber = "CE696KO";

  const goToOfficialControl = () => {
    // Home is the only screen for now
    // navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.screen}>
        {/* ===== HERO (UNCHANGED) ===== */}
        <View style={styles.heroWrap}>
          <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
        </View>

        {/* ===== Vérifié (bigger tick icon) ===== */}
        <View style={styles.statusRow}>
          <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
          <Text style={styles.statusText}>Vérifié</Text>
        </View>

        {/* ===== Plate (smaller) ===== */}
        <View style={styles.plateWrap}>
          <Text style={styles.plateText}>{plateNumber}</Text>
        </View>

        {/* ===== Button (icon bigger, mockup-like position) ===== */}
        <TouchableOpacity
          activeOpacity={0.92}
          style={styles.officialBtn}
          onPress={goToOfficialControl}
        >
          <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
          <Text style={styles.btnText}>Contrôle officiel</Text>
        </TouchableOpacity>

        {/* ===== Bottom logo (fit screen, no scroll) ===== */}
        <View style={styles.logoWrap}>
          <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
        </View>
      </View>
    </SafeAreaView>
  );
}

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#EEF3F7" },

  // ✅ no ScrollView — everything must fit
  screen: {
    flex: 1,
    paddingTop: 14,
    paddingHorizontal: 18,
    alignItems: "center",
    justifyContent: "flex-start",
  },

  /* ===== HERO (UNCHANGED) ===== */
  heroWrap: {
    width: "100%",
    alignItems: "center",
    justifyContent: "center",
    marginTop: 4,
  },
  taxi: {
    width: "100%",
    height: 300, // keep as-is (your taxi part is now correct)
  },

  /* ===== STATUS ===== */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 4,
    gap: 12,
  },

  // (1) ✅ bigger green check icon
  smallTick: { width: 56, height: 56 },

  statusText: {
    fontSize: 40,
    fontWeight: "900",
    color: GREEN,
    letterSpacing: 0.2,
  },

  /* ===== PLATE (4) smaller box + text ===== */
  plateWrap: {
    marginTop: 10,
    paddingHorizontal: 22,
    paddingVertical: 8,
    borderRadius: 12,
    borderWidth: 3,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
  },
  plateText: {
    fontSize: 40,
    fontWeight: "900",
    letterSpacing: 1,
    color: "#111827",
  },
// ✅ ONLY update these parts in your existing HomeScreen.js styles

officialBtn: {
  marginTop: 12,
  width: "72%",          // ✅ smaller button
  height: 54,            // ✅ smaller height
  backgroundColor: DARK_GREEN,
  borderRadius: 16,
  flexDirection: "row",
  alignItems: "center",
  justifyContent: "center",

  paddingLeft: 54,       // ✅ less space (smaller icon)
  paddingRight: 16,

  shadowColor: "#000",
  shadowOpacity: 0.20,
  shadowRadius: 16,
  shadowOffset: { width: 0, height: 12 },
  elevation: 7,
},

btnIcon: {
  position: "absolute",
  left: 16,
  width: 0,             // ✅ smaller icon
  height: 40,
  opacity: 0.98,

  // ✅ NO WHITE BORDER
  borderWidth: 0,
  borderColor: "transparent",
  borderRadius: 0,
  padding: 0,
},

btnText: {
  color: "#FFFFFF",
  fontSize: 20,          // ✅ smaller text
  fontWeight: "700",
  letterSpacing: 0.2,
},


  /* ===== LOGO ===== */
  logoWrap: {
    marginTop: 10,
    alignItems: "center",
    width: "100%",
    flex: 1,
    justifyContent: "flex-start",
  },

  // reduced so it fits without scrolling
  logo: {
    width: 210,
    height: 210,
  },
});
